// هيكل معلومات إنشاء Pipeline Layout
VkPipelineLayoutCreateInfo pipelineLayoutInfo = {};
pipelineLayoutInfo.sType = VK_STRUCTURE_TYPE_PIPELINE_LAYOUT_CREATE_INFO;

// Descriptor Set Layouts (للـ Uniforms و Textures)
pipelineLayoutInfo.setLayoutCount = 1; // عدد التخطيطات
pipelineLayoutInfo.pSetLayouts = &descriptorSetLayout;

// Push Constants (بيانات صغيرة سريعة)
VkPushConstantRange pushConstantRange = {};
pushConstantRange.stageFlags = VK_SHADER_STAGE_VERTEX_BIT;
pushConstantRange.offset = 0;
pushConstantRange.size = sizeof(PushConstantData);

pipelineLayoutInfo.pushConstantRangeCount = 1;
pipelineLayoutInfo.pPushConstantRanges = &pushConstantRange;

// إنشاء التخطيط
VkPipelineLayout pipelineLayout;
VkResult result = vkCreatePipelineLayout(
 device, &pipelineLayoutInfo, nullptr, &pipelineLayout
);

if (result != VK_SUCCESS) {
 throw std::runtime_error("فشل إنشاء Pipeline Layout!");
}
